	def _show_param_on_overlay(self, param):
		if not self.display_on_move:
			return
		try:
			now = time.time()
			if (now - self._last_display_time) < self.display_throttle_sec:
				return
			device_name = ""
			if hasattr(param, "canonical_parent") and param.canonical_parent:
				try:
					device_name = param.canonical_parent.name
				except:
					device_name = ""
			if not device_name:
				device_name = "Device"
			param_name = getattr(param, "name", "Param")
			value_text = ""
			if hasattr(param, "value_display"):
				value_text = param.value_display
			elif hasattr(param, "str_for_value"):
				try:
					value_text = param.str_for_value(param.value)
				except:
					value_text = ""
			if value_text == "":
				try:
					value_text = str(param.value)
				except:
					value_text = ""
			payload = (device_name, param_name, value_text)
			if payload == self._last_display_payload:
				return
			self._last_display_payload = payload
			self._last_display_time = now
			self._send_display_text(0, device_name)
			self._send_display_text(1, param_name)
			self._send_display_text(2, value_text)
			self._trigger_overlay_display()
		except:
			pass
